sql:
SELECT COUNT(member_id) AS member_count
FROM members
WHERE branch_id = 1;

external_knowledge:
- 'Top three champions' refers to the fundraisers with the highest amount raised in each branch; 
- 'Loyal supporters' refers to the members who have contributed to these top fundraisers;
- 'Generosity' refers to the amount each supporter has pledged to the fundraiser.

sql:
SELECT MIN(join_date) AS earliest_active_subscription
FROM members
WHERE subscription_status = 'active';

SELECT member_id, name
FROM members
ORDER BY member_id;

SELECT fundraiser_name, target_amount, amount_raised
FROM fundraisers
WHERE fundraiser_id = 0;

SELECT COUNT(*) AS member_count
FROM members
WHERE membership_type_id = (SELECT membership_type_id FROM membership_types WHERE membership_type_name = 'Individual (u25)');

external_knowledge:
- Big spenders are those who have made the highest total payments; 
- The past year refers to the 12-month period preceding the current date; 
- Being subscribed means having an active membership subscription.

sql:
SELECT SUM(amount_raised) AS total_raised
FROM fundraisers
WHERE fundraiser_id = 0;

SELECT SUM(amount_contributed) AS total_amount_raised
FROM member_fundraisers
WHERE fundraiser_id = (SELECT fundraiser_id FROM fundraisers WHERE fundraiser_name = 'River City Fundraiser');
